from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

def validate_token(token):
    try:
        decoded_token = jwt.decode(token, verify=False)
        return decoded_token
    except jwt.ExpiredSignatureError:
        return "Token has expired"
    except jwt.InvalidTokenError:
        return "Invalid token"

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def proxy(path):
    auth_header = request.headers.get('Authorization')
    if auth_header and auth_header.startswith("Bearer"):
        token = auth_header.split()[1]
        decoded_token = validate_token(token)
        
        if isinstance(decoded_token, str):
            return jsonify({'error': decoded_token}), 401
        
        # Assuming the backend service is also a Flask app
        backend_app = Flask(__name__)
        @backend_app.route('/' + path, methods=['GET', 'POST', 'PUT', 'DELETE'])
        def handle_request(*args, **kwargs):
            return request.method.upper() + " to " + path
        
        # Forward the request to the backend service
        with app.app_context():
            response = backend_app.handle_request(*args, **kwargs)
        
        return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)